import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            int max_sum = 0;
            for (int i = 0; i < N; i++) {
                int sum = 0;
                for (int j = i; j < N; j++) {
                    sum += arr[j];
                    max_sum = Math.max(max_sum, sum);
                }
            }
            System.out.println(max_sum);
        }
    }
}

