const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const arr = readline().split(' ').map(x => parseInt(x));
    let max_sum = 0;
    for (let j = 0; j < N; j++) {
        let sum = 0;
        for (let k = j; k < N; k++) {
            sum += arr[k];
            max_sum = Math.max(max_sum, sum);
        }
    }
    console.log(max_sum);
}
